  const dong = dongName;
  let _dh = 0;
  for(let i=0;i<dong.length;i++) _dh = (_dh*31+dong.charCodeAt(i))>>>0;
  const dInfoNums = [120+(_dh%231), 91+(_dh%9)];
  const gu = ak;
