  const SUBJECTS_LIST=[{en:'math',ko:'수학',emoji:'📐'},{en:'english',ko:'영어',emoji:'📖'},{en:'korean',ko:'국어',emoji:'✍️'},{en:'science',ko:'과학',emoji:'🔬'},{en:'social',ko:'사회',emoji:'🌏'},{en:'coding',ko:'코딩',emoji:'💻'},{en:'essay',ko:'논술',emoji:'📝'},{en:'gsd',ko:'검정고시',emoji:'📋'}];
